4	export class IntersectionType<MemberType extends TypeBuilder = TypeBuilder> extends TypeBuilder {
5	  needsParenthesisWhenIndexed = true
6	  needsParenthesisInKeyof = true
7	  readonly members: MemberType[]
8	
9	  constructor(firstType: MemberType) {
10	    super()
11	    this.members = [firstType]
12	  }
13	
14	  addType(type: MemberType) {
15	    this.members.push(type)
16	    return this
17	  }
18	
19	  addTypes(types: MemberType[]) {
20	    for (const type of types) {
21	      this.addType(type)
22	    }
23	    return this
24	  }
25	
26	  write(writer: Writer): void {
27	    writer.writeJoined(' & ', this.members, (member, writer) => {
28	      if (member.needsParenthesisInIntersection) {
29	        writer.write('(').write(member).write(')')
30	      } else {
31	        writer.write(member)
32	      }
33	    })
34	  }
