36	  mapTypes<NewMemberType extends TypeBuilder>(
37	    callback: (type: MemberType) => NewMemberType,
38	  ): IntersectionType<NewMemberType> {
39	    return intersectionType(this.members.map((m) => callback(m)))
40	  }
41	}
