import { isValidJsIdentifier } from '@prisma/internals'

import { BasicBuilder } from './BasicBuilder'
import { DocComment } from './DocComment'
import { TypeBuilder } from './TypeBuilder'
import { WellKnownSymbol } from './WellKnownSymbol'
import { Writer } from './Writer'

export class Property implements BasicBuilder {
  private isOptional = false
  private isReadonly = false
  private docComment?: DocComment

  constructor(
    private name: string | WellKnownSymbol,
    private type: TypeBuilder,
  ) {}

  optional(): this {
    this.isOptional = true
    return this
  }

  readonly(): this {
    this.isReadonly = true
    return this
  }

  setDocComment(docComment: DocComment): this {
    this.docComment = docComment
    return this
  }

  write(writer: Writer): void {
    if (this.docComment) {
      writer.write(this.docComment)
    }
    if (this.isReadonly) {
      writer.write('readonly ')
    }

    if (typeof this.name === 'string') {
      if (isValidJsIdentifier(this.name)) {
        writer.write(this.name)
      } else {
        writer.write('[').write(JSON.stringify(this.name)).write(']')
      }
    } else {
      writer.write('[').write(this.name).write(']')
    }

    if (this.isOptional) {
      writer.write('?')
    }
    writer.write(': ').write(this.type)
  }
}

export function property(name: string | WellKnownSymbol, type: TypeBuilder) {
  return new Property(name, type)
}

import { TypeBuilder } from './TypeBuilder'
import { Writer } from './Writer'

export class PrimitiveType extends TypeBuilder {
  constructor(private name: string) {
    super()
  }

  write(writer: Writer): void {
    writer.write(this.name)
  }
}

export const stringType = new PrimitiveType('string')
export const numberType = new PrimitiveType('number')
export const booleanType = new PrimitiveType('boolean')
export const nullType = new PrimitiveType('null')
export const undefinedType = new PrimitiveType('undefined')
export const bigintType = new PrimitiveType('bigint')
export const unknownType = new PrimitiveType('unknown')
export const anyType = new PrimitiveType('any')
export const voidType = new PrimitiveType('void')
export const thisType = new PrimitiveType('this')
export const neverType = new PrimitiveType('never')

import { assertNever } from '@prisma/internals'

import { BasicBuilder } from './BasicBuilder'
import { Writer } from './Writer'

type StringifyOptions = {
  indentLevel?: number
  newLine?: 'none' | 'leading' | 'trailing' | 'both'
}

export function stringify(builder: BasicBuilder, { indentLevel = 0, newLine = 'none' }: StringifyOptions = {}) {
  const str = new Writer(indentLevel, undefined).write(builder).toString()
  switch (newLine) {
    case 'none':
      return str
    case 'leading':
      return '\n' + str
    case 'trailing':
      return str + '\n'
    case 'both':
      return '\n' + str + '\n'
    default:
      assertNever(newLine, 'Unexpected value')
  }
}

