import {
  arrayType,
  booleanType,
  namedType,
  numberType,
  stringType,
  TypeBuilder,
  unknownType,
} from '@prisma/ts-builders'

/**
 * Maps a DMMF scalar type name to the TypeScript type used in the generated REST client.
 *
 * BigInt, Decimal, DateTime, and Bytes are represented as `string` for JSON-over-HTTP safety.
 * Json becomes `unknown` to allow arbitrary payloads.
 */
export function scalarToTypeBuilder(dmmfType: string, isList: boolean): TypeBuilder {
  const base = resolveScalar(dmmfType)
  return isList ? arrayType(base) : base
}

function resolveScalar(dmmfType: string): TypeBuilder {
  switch (dmmfType) {
    case 'String':
      return stringType
    case 'Boolean':
      return booleanType
    case 'Int':
    case 'Float':
      return numberType
    case 'BigInt':
    case 'Decimal':
    case 'DateTime':
    case 'Bytes':
      // Serialised as strings across JSON/HTTP boundaries.
      return stringType
    case 'Json':
      return unknownType
    default:
      // Enum or unsupported scalar — reference the generated type by name.
      return namedType(dmmfType)
  }
}

