import type { DMMF } from '@prisma/dmmf'
import {
  array,
  interfaceDeclaration,
  moduleExport,
  namedType,
  numberType,
  property,
  stringType,
  stringify,
  typeDeclaration,
  undefinedType,
  unionType,
} from '@prisma/ts-builders'

import { scalarToTypeBuilder } from './type-map'

/**
 * Returns the kebab-case plural URL segment for a model name.
 *
 * Examples: `User` → `/users`, `BlogPost` → `/blog-posts`.
 */
function modelToUrlPath(modelName: string): string {
  const kebab = modelName
    // Insert a hyphen between a lowercase letter (or digit) and an uppercase letter.
    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
    .toLowerCase()
  return `/${kebab}s`
}

/** Scalar fields only — relation fields are excluded from interfaces and inputs. */
function scalarFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

/**
 * Builds the TypeScript source declarations for a single Prisma model and returns
 * them as a string ready to be appended to the output file.
 *
 * Emits (all exported):
 *   - `<Model>` interface — every scalar field with correct optionality
 *   - `<Model>WhereUniqueInput` — only `@id` and `@unique` fields, all optional
 *   - `<Model>CreateInput` — writable fields; auto-generated defaults marked optional
 *   - `<Model>UpdateInput` — all scalar fields optional, IDs excluded
 *   - `<Model>FindManyArgs` — `where?`, `skip?`, `take?`
 *   - `create<Model>Client(baseUrl)` factory function
 */
export function generateModelDeclarations(model: DMMF.Model): string {
  const scalars = scalarFields(model)
  const name = model.name

  // ── <Model> interface ────────────────────────────────────────────────────────
  const modelInterface = interfaceDeclaration(name)
  for (const field of scalars) {
    const prop = property(field.name, scalarToTypeBuilder(field.type, field.isList))
    if (!field.isRequired || field.hasDefaultValue) {
      prop.optional()
    }
    modelInterface.add(prop)
  }

  // ── <Model>WhereUniqueInput ──────────────────────────────────────────────────
  const whereUniqueInterface = interfaceDeclaration(`${name}WhereUniqueInput`)
  for (const field of scalars.filter((f) => f.isId || f.isUnique)) {
    whereUniqueInterface.add(property(field.name, scalarToTypeBuilder(field.type, field.isList)).optional())
  }

  // ── <Model>CreateInput ───────────────────────────────────────────────────────
  // Exclude auto-generated fields (isGenerated) and treat fields with defaults as optional.
  const createInterface = interfaceDeclaration(`${name}CreateInput`)
  for (const field of scalars.filter((f) => !f.isGenerated)) {
    const prop = property(field.name, scalarToTypeBuilder(field.type, field.isList))
    if (!field.isRequired || field.hasDefaultValue) {
      prop.optional()
    }
    createInterface.add(prop)
  }

  // ── <Model>UpdateInput ───────────────────────────────────────────────────────
  // IDs are excluded; every remaining field is optional.
  const updateInterface = interfaceDeclaration(`${name}UpdateInput`)
  for (const field of scalars.filter((f) => !f.isId)) {
    updateInterface.add(property(field.name, scalarToTypeBuilder(field.type, field.isList)).optional())
  }

  // ── <Model>FindManyArgs ──────────────────────────────────────────────────────
  const findManyInterface = interfaceDeclaration(`${name}FindManyArgs`)
  findManyInterface.add(property('where', namedType(`${name}WhereUniqueInput`)).optional())
  findManyInterface.add(property('skip', numberType).optional())
  findManyInterface.add(property('take', numberType).optional())

  // ── String literals used in the factory implementation ───────────────────────
  const urlPath = modelToUrlPath(name)

  const declarations = [
    stringify(moduleExport(modelInterface), { newLine: 'trailing' }),
    stringify(moduleExport(whereUniqueInterface), { newLine: 'trailing' }),
    stringify(moduleExport(createInterface), { newLine: 'trailing' }),
    stringify(moduleExport(updateInterface), { newLine: 'trailing' }),
    stringify(moduleExport(findManyInterface), { newLine: 'trailing' }),
  ].join('\n')

  // ── Factory function (raw template literal — ts-builders has no body builder) ─
  const factoryFn = `
export function create${name}Client(baseUrl: string) {
  const url = \`\${baseUrl}${urlPath}\`
  return {
    async findMany(args?: ${name}FindManyArgs): Promise<${name}[]> {
      const params = new URLSearchParams()
      if (args?.skip != null) params.set('skip', String(args.skip))
      if (args?.take != null) params.set('take', String(args.take))
      const qs = params.size > 0 ? \`?\${params}\` : ''
      const res = await fetch(\`\${url}\${qs}\`)
      if (!res.ok) throw new Error(\`findMany ${name} failed: \${res.status}\`)
      return res.json() as Promise<${name}[]>
    },
    async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
      const params = new URLSearchParams(Object.entries(where).map(([k, v]) => [k, String(v)]))
      const res = await fetch(\`\${url}?\${params}\`)
      if (res.status === 404) return null
      if (!res.ok) throw new Error(\`findUnique ${name} failed: \${res.status}\`)
      return res.json() as Promise<${name}>
    },
    async create(data: ${name}CreateInput): Promise<${name}> {
      const res = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })
      if (!res.ok) throw new Error(\`create ${name} failed: \${res.status}\`)
      return res.json() as Promise<${name}>
    },
    async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
      const params = new URLSearchParams(Object.entries(where).map(([k, v]) => [k, String(v)]))
      const res = await fetch(\`\${url}?\${params}\`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })
      if (!res.ok) throw new Error(\`update ${name} failed: \${res.status}\`)
      return res.json() as Promise<${name}>
    },
    async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
      const params = new URLSearchParams(Object.entries(where).map(([k, v]) => [k, String(v)]))
      const res = await fetch(\`\${url}?\${params}\`, { method: 'DELETE' })
      if (!res.ok) throw new Error(\`delete ${name} failed: \${res.status}\`)
      return res.json() as Promise<${name}>
    },
  }
}
`

  return declarations + factoryFn
}

