import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { generateModelDeclarations } from './model-file-generator'

const FILE_HEADER = `\
/**
 * Generated by @prisma/rest-client-generator — do not edit manually.
 */
`

/**
 * Orchestrates code generation for all models and writes the output `index.ts`
 * into the generator's configured output directory.
 */
export async function generateClient(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('@prisma/rest-client-generator: no output directory configured')
  }

  await fs.mkdir(outputDir, { recursive: true })

  const parts: string[] = [FILE_HEADER]

  for (const model of options.dmmf.datamodel.models) {
    parts.push(generateModelDeclarations(model))
  }

  const outputPath = path.join(outputDir, 'index.ts')
  await fs.writeFile(outputPath, parts.join('\n'), 'utf-8')
}

