  interfaceDeclaration,
  moduleExport,
  namedType,
  numberType,
  property,
  stringType,
  stringify,
  typeDeclaration,
  undefinedType,
  unionType,
} from '@prisma/ts-builders'

import { scalarToTypeBuilder } from './type-map'

/**
 * Returns the kebab-case plural URL segment for a model name.
 *
 * Examples: `User` → `/users`, `BlogPost` → `/blog-posts`.
 */
function modelToUrlPath(modelName: string): string {
  const kebab = modelName
    // Insert a hyphen between a lowercase letter (or digit) and an uppercase letter.
    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
    .toLowerCase()
  return `/${kebab}s`
}

/** Scalar fields only — relation fields are excluded from interfaces and inputs. */
function scalarFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
